public class Main {
    public static void main(String[] args) {
        int age = 25; // Variable declaration and initialization
        String name = "Alice";
        System.out.println(name + " is " + age + " years old.");
    }
}

public class Student {
    // Instance variables
    String name;
    int rollNo;

    public Student(String studentName, int studentRollNo) {
        // Local variables passed as parameters
        name = studentName;
        rollNo = studentRollNo;
    }

    public void display() {
        System.out.println("Name: " + name + ", Roll No: " + rollNo);
    }

    public static void main(String[] args) {
        Student s1 = new Student("Bob", 101);
        s1.display();
    }
}

public class Counter {
    // Static variable shared across all instances
    static int count = 0;

    public Counter() {
        count++; // Incrementing the shared variable
        System.out.println("Current Count: " + count);
    }

    public static void main(String[] args) {
        Counter c1 = new Counter();
        Counter c2 = new Counter();
        Counter c3 = new Counter();
    }
}

